from flask import Flask, request, jsonify
import face_recognition
import os

app = Flask(__name__)

# Load employee photos and encode them
employee_photos_dir = 'path/to/employee/photos'
employee_encodings = {}
employee_names = []

for filename in os.listdir(employee_photos_dir):
    if filename.endswith(".jpg") or filename.endswith(".png"):
        image_path = os.path.join(employee_photos_dir, filename)
        image = face_recognition.load_image_file(image_path)
        encoding = face_recognition.face_encodings(image)[0]
        employee_encodings[filename] = encoding
        employee_names.append(filename)

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400

    image_file = request.files['image']
    image_bytes = image_file.read()
    image = face_recognition.load_image_file(image_bytes)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({'error': 'No faces found in the image'}), 400

    results = []
    for encoding in face_encodings:
        matches = face_recognition.compare_faces(list(employee_encodings.values()), encoding)
        name = "Unknown"
        confidence_scores = [1.0 if match else 0.0 for match in matches]
        max_score_index = confidence_scores.index(max(confidence_scores))
        if max_score_index < len(employee_names):
            name = employee_names[max_score_index]
        results.append({'name': name, 'confidence_scores': confidence_scores})

    return jsonify(results)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)